def validate(args, outputs):
    ops, arg_lists = args
    if not isinstance(outputs, list) or len(outputs) != len(ops):
        return False
    if ops[0] != 'Solution':
        return False
    rects = arg_lists[0][0]
    for i in range(1, len(ops)):
        op, out = ops[i], outputs[i]
        if op == 'pick':
            if not (isinstance(out, list) and len(out) == 2):
                return False
            x, y = out
            if not isinstance(x, int) or isinstance(x, bool):
                return False
            if not isinstance(y, int) or isinstance(y, bool):
                return False
            ok = False
            for x1, y1, x2, y2 in rects:
                if x1 <= x <= x2 and y1 <= y <= y2:
                    ok = True
                    break
            if not ok:
                return False
    return True

