function validate(args, outputs) {
  const [ops, argLists] = args;
  if (!Array.isArray(outputs) || outputs.length !== ops.length) return false;
  if (ops[0] !== 'Solution') return false;
  const rects = argLists[0][0];
  for (let i = 1; i < ops.length; i++) {
    const op = ops[i], out = outputs[i];
    if (op === 'pick') {
      if (!Array.isArray(out) || out.length !== 2) return false;
      const [x, y] = out;
      if (typeof x !== 'number' || !Number.isInteger(x)) return false;
      if (typeof y !== 'number' || !Number.isInteger(y)) return false;
      let ok = false;
      for (const [x1, y1, x2, y2] of rects) {
        if (x1 <= x && x <= x2 && y1 <= y && y <= y2) { ok = true; break; }
      }
      if (!ok) return false;
    }
  }
  return true;
}

