var Solution = function(rects) {
    this.rects = rects;
    this.prefix = [];
    let total = 0;
    for (const [x1, y1, x2, y2] of rects) {
        total += (x2 - x1 + 1) * (y2 - y1 + 1);
        this.prefix.push(total);
    }
    this.total = total;
};

Solution.prototype.pick = function() {
    const target = Math.floor(Math.random() * this.total) + 1;
    let lo = 0, hi = this.prefix.length - 1;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (this.prefix[mid] < target) lo = mid + 1;
        else hi = mid;
    }
    const [x1, y1, x2, y2] = this.rects[lo];
    const x = x1 + Math.floor(Math.random() * (x2 - x1 + 1));
    const y = y1 + Math.floor(Math.random() * (y2 - y1 + 1));
    return [x, y];
};
